// Generated by Claude Sonnet 4.5

import { FastifyInstance } from 'fastify';

import { baseApiPath } from '@/constants/config';
import { setup, teardown } from '@/utils/appBuilder';

jest.mock('@/routes/api/helpers/getServiceAccountToken');
jest.mock('@/routes/api/helpers/getToken');
jest.mock('@/routes/api/helpers/getDevWorkspaceClient');
jest.mock('@/services/kubeclient/kubeConfigProvider');

// Mock RegistryApiService
const mockListBackupImages = jest.fn();
const mockValidateBackupImage = jest.fn();
jest.mock('@/devworkspaceClient/services/registryApi', () => ({
  RegistryApiService: jest.fn().mockImplementation(() => ({
    listBackupImages: mockListBackupImages,
    validateBackupImage: mockValidateBackupImage,
  })),
}));

describe('Route Registration Integration Tests', () => {
  let app: FastifyInstance;
  const namespace = 'user-che';

  const setupDefaultMocks = () => {
    mockListBackupImages.mockResolvedValue({
      items: [],
      total: 0,
    });

    mockValidateBackupImage.mockResolvedValue({
      valid: true,
    });
  };

  beforeAll(async () => {
    setupDefaultMocks();
    app = await setup();
  });

  afterAll(() => {
    teardown(app);
  });

  afterEach(() => {
    jest.clearAllMocks();
    setupDefaultMocks();
  });

  describe('Backup Routes Registration', () => {
    it('should register backup status route and be accessible', async () => {
      const res = await app
        .inject()
        .get(`${baseApiPath}/namespace/${namespace}/devworkspaces/my-workspace/backup-status`);

      expect(res.statusCode).toBeLessThan(500);
      expect(res.statusCode).not.toBe(404);
    });

    it('should register list backups route and be accessible', async () => {
      const res = await app.inject().get(`${baseApiPath}/namespace/${namespace}/backups`);

      expect(res.statusCode).toBeLessThan(500);
      expect(res.statusCode).not.toBe(404);
    });

    it('should register validate backup route and be accessible', async () => {
      const res = await app
        .inject()
        .post(`${baseApiPath}/namespace/${namespace}/backups/validate`)
        .payload({ imageUrl: 'quay.io/test/backup:latest' });

      expect(res.statusCode).toBeLessThan(500);
      expect(res.statusCode).not.toBe(404);
    });
  });

  describe('Route Conflicts', () => {
    it('should not conflict with existing devworkspace routes', async () => {
      const res = await app.inject().get(`${baseApiPath}/namespace/${namespace}/devworkspaces`);

      expect(res.statusCode).toBeLessThan(500);
      expect(res.statusCode).not.toBe(404);
    });

    it('should not conflict with pods routes', async () => {
      const res = await app.inject().get(`${baseApiPath}/namespace/${namespace}/pods`);

      expect(res.statusCode).toBeLessThan(500);
      expect(res.statusCode).not.toBe(404);
    });

    it('should properly differentiate between backup routes', async () => {
      const listRes = await app.inject().get(`${baseApiPath}/namespace/${namespace}/backups`);

      const validateRes = await app
        .inject()
        .post(`${baseApiPath}/namespace/${namespace}/backups/validate`)
        .payload({ imageUrl: 'test-url' });

      expect(listRes.statusCode).toBeLessThan(500);
      expect(validateRes.statusCode).toBeLessThan(500);
      expect(listRes.statusCode).not.toBe(404);
      expect(validateRes.statusCode).not.toBe(404);
    });
  });

  describe('Error Handling Middleware', () => {
    it('should handle validation errors in backup validate route', async () => {
      const res = await app
        .inject()
        .post(`${baseApiPath}/namespace/${namespace}/backups/validate`)
        .payload({ imageUrl: '' });

      expect(res.statusCode).toEqual(400);
      expect(res.json()).toHaveProperty('message');
    });
  });

  describe('CORS Headers', () => {
    it('should apply CORS headers to backup list route', async () => {
      const res = await app.inject().get(`${baseApiPath}/namespace/${namespace}/backups`);

      expect(res.headers).toBeDefined();
      expect(res.statusCode).toBeLessThan(500);
    });

    it('should apply CORS headers to POST backup routes', async () => {
      const res = await app
        .inject()
        .post(`${baseApiPath}/namespace/${namespace}/backups/validate`)
        .payload({ imageUrl: 'test-url' });

      expect(res.headers).toBeDefined();
      expect(res.statusCode).toBeLessThan(500);
    });
  });

  describe('Swagger Documentation', () => {
    it('should include backup routes in swagger spec', async () => {
      const res = await app.inject().get('/dashboard/api/swagger/json');

      expect(res.statusCode).toEqual(200);
      const swagger = res.json();

      expect(swagger.paths).toBeDefined();
      const backupRoutes = Object.keys(swagger.paths).filter(path => path.includes('backup'));
      expect(backupRoutes.length).toBeGreaterThan(0);
    });

    it('should tag backup routes with "Backup" tag', async () => {
      const res = await app.inject().get('/dashboard/api/swagger/json');

      expect(res.statusCode).toEqual(200);
      const swagger = res.json();

      const backupRoute = Object.keys(swagger.paths).find(path => path.includes('backup-status'));
      if (backupRoute) {
        const routeSpec = swagger.paths[backupRoute];
        const method = Object.keys(routeSpec)[0];
        expect(routeSpec[method].tags).toContain('Backup');
      }
    });
  });

  describe('HTTP Method Validation', () => {
    it('should reject POST to GET-only backup list route', async () => {
      const res = await app
        .inject()
        .post(`${baseApiPath}/namespace/${namespace}/backups`)
        .payload({});

      expect([404, 405]).toContain(res.statusCode);
    });

    it('should reject GET to POST-only backup validate route', async () => {
      const res = await app.inject().get(`${baseApiPath}/namespace/${namespace}/backups/validate`);

      expect([404, 405]).toContain(res.statusCode);
    });
  });

  describe('Route Parameter Validation', () => {
    it('should route backup list with an empty namespace without a server error', async () => {
      const res = await app.inject().get(`${baseApiPath}/namespace//backups`);

      expect(res.statusCode).toBeLessThan(500);
    });

    it('should validate required workspace name in backup status route', async () => {
      const res = await app
        .inject()
        .get(`${baseApiPath}/namespace/${namespace}/devworkspaces//backup-status`);

      expect([200, 400, 404]).toContain(res.statusCode);
    });
  });

  describe('Authentication Middleware', () => {
    it('should apply authentication to backup routes', async () => {
      const res = await app
        .inject()
        .get(`${baseApiPath}/namespace/${namespace}/devworkspaces/test/backup-status`);

      expect(res.statusCode).toBeLessThan(500);
      expect(res.statusCode).not.toBe(404);
    });
  });

  describe('Backwards Compatibility', () => {
    it('should not break existing server-config route', async () => {
      const res = await app.inject().get(`${baseApiPath}/server-config`);

      expect(res.statusCode).toBeLessThan(500);
    });

    it('should not break existing user-profile route', async () => {
      const res = await app.inject().get(`${baseApiPath}/userprofile/${namespace}`);

      expect(res.statusCode).not.toBe(404);
    });

    it('should preserve existing devworkspaces routes', async () => {
      const routes = app.printRoutes();

      expect(routes).toContain('devworkspace');
    });
  });

  describe('Route Accessibility via Print Routes', () => {
    it('should list backup-status route in routes tree', () => {
      const routes = app.printRoutes();

      expect(routes).toContain('/backup-status');
      // Note: 'backups' path is factored out character-by-character in printRoutes() tree
      // visualization, so we verify it via actual route calls in other tests
    });

    it('should list validate backup route', () => {
      const routes = app.printRoutes();

      expect(routes).toContain('validate');
    });
  });
});
